// frontend/src/components/LeanConnect.tsx
import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';
import callbackManager from '../services/leanCallbackManager';

const API_URL = 'http://localhost:3001';

declare global {
    interface Window {
        Lean: any;
    }
}

interface LeanConnectProps {
    customerId: string;
    onSuccess: (entityId: string) => void;
    onError: (error: string) => void;
}

const LeanConnect: React.FC<LeanConnectProps> = ({ customerId, onSuccess, onError }) => {
    const [loading, setLoading] = useState(false);
    const [status, setStatus] = useState<string>('');
    const connectionInProgress = useRef(false);

    // ✅ Register the callback ONCE when the component mounts
    useEffect(() => {
        console.log('🔄 Registering global Lean callback...');
        callbackManager.setCallback((response: any) => {
            console.log('📨 Callback triggered with response:', response);
            setLoading(false);
            connectionInProgress.current = false;

            if (response.status === 'SUCCESS') {
                setStatus('✅ Bank connected successfully!');
                onSuccess(response.entity_id || 'success');
            } else if (response.status === 'ERROR') {
                const errorMsg = response.message || 'Failed to connect bank';
                setStatus('❌ Error: ' + errorMsg);
                onError(errorMsg);
            } else if (response.status === 'CANCEL') {
                setStatus('⏹️ User cancelled');
                onError('User cancelled the bank connection');
            } else {
                setStatus('⚠️ Unknown response: ' + JSON.stringify(response));
                onError('Unexpected response from Lean');
            }
        });

        // Cleanup on unmount
        return () => {
            callbackManager.clearCallback();
        };
    }, []);

    const handleConnect = async () => {
        // ✅ Prevent multiple simultaneous connections
        if (connectionInProgress.current || callbackManager.isProcessingConnection()) {
            console.log('⏳ Connection already in progress, ignoring...');
            setStatus('⏳ Connection already in progress...');
            return;
        }

        connectionInProgress.current = true;
        callbackManager.setProcessing(true);
        setLoading(true);
        setStatus('🔐 Getting customer token...');

        try {
            // 1. Get customer-scoped token
            console.log('🔑 Fetching customer token for:', customerId);
            const tokenResponse = await axios.get(`${API_URL}/api/lean/customer-token`, {
                params: { customerId }
            });

            if (!tokenResponse.data.success) {
                throw new Error('Failed to get customer token: ' + (tokenResponse.data.error || 'Unknown error'));
            }

            const customerToken = tokenResponse.data.customerToken;
            const appToken = '730a9f67-7149-49e5-988d-30200b8fa695';

            console.log('✅ Customer token received');

            // 2. The callback is already registered from useEffect

            // 3. Call Lean.connect()
            console.log('🔄 Calling Lean.connect()...');
            window.Lean.connect({
                access_token: customerToken,
                app_token: appToken,
                customer_id: customerId,
                permissions: ['identity', 'accounts', 'balance', 'transactions'],
                sandbox: true,
                debug: true
            });

            setStatus('🔄 Waiting for bank authorization...');
            console.log('✅ Lean.connect() called, waiting for callback...');

            // ✅ Safety timeout: auto-reset after 60 seconds
            setTimeout(() => {
                if (connectionInProgress.current) {
                    console.warn('⏰ Connection timeout after 60 seconds');
                    connectionInProgress.current = false;
                    callbackManager.setProcessing(false);
                    setLoading(false);
                    setStatus('⏰ Connection timed out. Please try again.');
                    onError('Connection timeout');
                }
            }, 60000);

        } catch (error: any) {
            console.error('❌ Lean connect error:', error);
            setStatus('❌ Error: ' + error.message);
            onError(error.message || 'Failed to initiate bank connection');
            setLoading(false);
            connectionInProgress.current = false;
            callbackManager.setProcessing(false);
        }
    };

    return (
        <div className="lean-connect">
            <button
                onClick={handleConnect}
                disabled={loading}
                className="btn-connect"
                style={{
                    width: '100%',
                    padding: '12px',
                    background: loading ? '#a0aec0' : 'linear-gradient(135deg, #006a4e, #00875a)',
                    color: '#fff',
                    border: 'none',
                    borderRadius: '10px',
                    fontSize: '16px',
                    fontWeight: '600',
                    cursor: loading ? 'not-allowed' : 'pointer',
                    transition: 'transform 0.2s, box-shadow 0.2s'
                }}
                onMouseEnter={(e) => {
                    if (!loading) {
                        e.currentTarget.style.transform = 'translateY(-2px)';
                        e.currentTarget.style.boxShadow = '0 4px 16px rgba(0, 106, 78, 0.35)';
                    }
                }}
                onMouseLeave={(e) => {
                    e.currentTarget.style.transform = 'translateY(0)';
                    e.currentTarget.style.boxShadow = 'none';
                }}
            >
                {loading ? '⏳ Connecting...' : '🔗 Connect Bank Account'}
            </button>
            {status && (
                <p style={{
                    marginTop: 8,
                    fontSize: 13,
                    color: status.includes('✅') ? '#22543d' : status.includes('❌') ? '#9b2c2c' : '#2b6cb0'
                }}>
                    {status}
                </p>
            )}
        </div>
    );
};

export default LeanConnect;
